// Timeout + Retry with exponential backoff
public <T> T callWithRetry(Callable<T> task, int maxRetries, long initialBackoff) throws Exception {
    long backoff = initialBackoff;
    for(int i = 0; i <= maxRetries; i++) {
        try {
            return task.call();
        } catch(TimeoutException | TemporaryException e) {
            if(i == maxRetries) throw e;
            long jitter = (long)(backoff * Math.random());
            Thread.sleep(backoff + jitter);
            backoff *= 2; // Exponential: 100ms, 200ms, 400ms, ...
        }
    }
    return null;
}

